module top_module(
    input [3:0] a,
    input [3:0] b,
    output reg le,
    output reg lt,
    output reg eq
);always @(*) begin
        if (a > b) begin
            le = 1;
            lt = 0;
            eq = 0;
        end else if (a < b) begin
            le = 0;
            lt = 1;
            eq = 0;
        end else begin
            le = 0;
            lt = 0;
            eq = 1;
        end
    end

endmodule
